import{_ as n,c as a,e,o as p}from"./app-CjRmnyLj.js";const t={};function o(l,s){return p(),a("div",null,[...s[0]||(s[0]=[e(`<h1 id="gowind-admin-风行-—-开箱即用的企业级全栈中后台框架-前端权限控制" tabindex="-1"><a class="header-anchor" href="#gowind-admin-风行-—-开箱即用的企业级全栈中后台框架-前端权限控制"><span>GoWind Admin｜风行 — 开箱即用的企业级全栈中后台框架：前端权限控制</span></a></h1><p>在企业级中后台系统中，前端权限控制是保障数据安全、规范用户操作边界的核心能力。风行·GoWind Admin 前端权限控制核心聚焦于<strong>功能权限管控</strong>，根据控制粒度的不同，分为「页面级权限」和「按钮级权限」两大模块，覆盖从“页面访问”到“操作执行”的全链路权限管控需求。本文将详细拆解两种权限的实现原理、启用方式、核心代码及最佳实践，助力开发者快速落地权限管控方案。</p><h2 id="一、页面级权限-管控页面访问边界" tabindex="-1"><a class="header-anchor" href="#一、页面级权限-管控页面访问边界"><span>一、页面级权限：管控页面访问边界</span></a></h2><p>页面级权限的核心目标是控制用户能否访问特定页面，主要通过「菜单隐藏」和「路由拦截」两种手段实现——未授权用户既无法在侧边栏看到目标菜单，也无法通过直接输入URL跳过菜单访问页面，进而实现对用户访问“财务报表”“人事管理”等核心页面的精准管控。</p><p>根据路由配置的管控主体不同，页面级权限分为「后端控制」和「前端控制」两种模式，适配不同复杂度的权限场景，开发者可根据项目需求灵活选择。</p><h3 id="_1-1-后端控制模式-推荐复杂权限场景" tabindex="-1"><a class="header-anchor" href="#_1-1-后端控制模式-推荐复杂权限场景"><span>1.1 后端控制模式（推荐复杂权限场景）</span></a></h3><h4 id="核心原理" tabindex="-1"><a class="header-anchor" href="#核心原理"><span>核心原理</span></a></h4><p>采用“后端动态下发路由”的方式实现权限管控：前端启动时仅初始化通用路由（如登录页、403页），登录后通过调用后端接口获取「符合当前用户权限的路由配置数据」，前端将该数据转换为框架可识别的路由结构后，通过 <code>router.addRoute</code> 动态添加到路由实例中，最终实现页面权限的动态适配。</p><h4 id="适用场景与优缺点" tabindex="-1"><a class="header-anchor" href="#适用场景与优缺点"><span>适用场景与优缺点</span></a></h4><ul><li><strong>适用场景</strong>：企业级复杂权限系统（如多租户、多角色动态配置、权限频繁变更）、需要统一管控路由配置的场景。</li><li><strong>优点</strong>：权限配置完全由后端统一管控，前端无需修改代码即可适配权限变更，扩展性强、维护成本低。</li><li><strong>缺点</strong>：需前后端协同定义路由数据格式，前端需开发路由数据转换逻辑，初期开发成本略高。</li></ul><h4 id="启用步骤与核心配置" tabindex="-1"><a class="header-anchor" href="#启用步骤与核心配置"><span>启用步骤与核心配置</span></a></h4><h5 id="_1-修改环境变量" tabindex="-1"><a class="header-anchor" href="#_1-修改环境变量"><span>1. 修改环境变量：</span></a></h5><p>编辑前端项目根目录的<code>.env</code> 配置文件，将 <code>VITE_ROUTER_ACCESS_MODE</code> 的值设置为 <code>backend</code>，启用后端控制模式：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"># 路由的访问模式：frontend（前端控制），backend（后端控制）</span>
<span class="line"><span class="token constant">VITE_ROUTER_ACCESS_MODE</span><span class="token operator">=</span>backend</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_2-核心逻辑代码" tabindex="-1"><a class="header-anchor" href="#_2-核心逻辑代码"><span>2.核心逻辑代码：</span></a></h5><p>后端路由的获取与动态生成逻辑封装在 <code>src/router/access.ts</code> 文件中，核心代码如下：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">generateAccess</span><span class="token punctuation">(</span>options<span class="token operator">:</span> GenerateMenuAndRoutesOptions<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token comment">// 其他初始化逻辑...</span></span>
<span class="line"></span>
<span class="line">  <span class="token comment">// 核心：根据访问模式生成可访问路由，后端模式下通过接口拉取路由数据</span></span>
<span class="line">  <span class="token keyword">return</span> <span class="token keyword">await</span> <span class="token function">generateAccessible</span><span class="token punctuation">(</span>preferences<span class="token punctuation">.</span>app<span class="token punctuation">.</span>accessMode<span class="token punctuation">,</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token operator">...</span>options<span class="token punctuation">,</span></span>
<span class="line">    <span class="token comment">// 异步拉取后端路由配置的方法</span></span>
<span class="line">    <span class="token function-variable function">fetchMenuListAsync</span><span class="token operator">:</span> <span class="token keyword">async</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">      <span class="token comment">// 加载中提示</span></span>
<span class="line">      message<span class="token punctuation">.</span><span class="token function">loading</span><span class="token punctuation">(</span><span class="token punctuation">{</span></span>
<span class="line">        content<span class="token operator">:</span> <span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span><span class="token function">$t</span><span class="token punctuation">(</span><span class="token string">&#39;common.loadingMenu&#39;</span><span class="token punctuation">)</span><span class="token interpolation-punctuation punctuation">}</span></span><span class="token string">...</span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">,</span></span>
<span class="line">        duration<span class="token operator">:</span> <span class="token number">1.5</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">      <span class="token comment">// 调用后端接口获取路由数据（defRouterService为后端生成的API客户端）</span></span>
<span class="line">      <span class="token keyword">const</span> data <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token keyword">await</span> defRouterService<span class="token punctuation">.</span><span class="token function">ListRoute</span><span class="token punctuation">(</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">??</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">      <span class="token comment">// 返回路由列表（需与后端约定数据结构：items为路由数组）</span></span>
<span class="line">      <span class="token keyword">return</span> data<span class="token punctuation">.</span>items <span class="token operator">??</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token comment">// 其他配置...</span></span>
<span class="line">  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h6 id="关键注意事项" tabindex="-1"><a class="header-anchor" href="#关键注意事项"><span>关键注意事项</span></a></h6><ol><li>前后端数据格式约定：需确保后端返回的路由数据包含 <code>path</code>（路由路径）、<code>name</code>（路由名称）、<code>meta</code>（菜单信息/权限标识）等核心字段，否则前端无法正常转换为可用路由。</li><li>异常处理：需补充接口请求失败的降级逻辑（如返回空路由列表，引导用户重新登录），避免因后端服务异常导致前端路由加载失败。</li></ol><h3 id="_1-2-前端控制模式-适配简单固定角色场景" tabindex="-1"><a class="header-anchor" href="#_1-2-前端控制模式-适配简单固定角色场景"><span>1.2 前端控制模式（适配简单固定角色场景）</span></a></h3><h4 id="核心原理-1" tabindex="-1"><a class="header-anchor" href="#核心原理-1"><span>核心原理</span></a></h4><p>采用“前端预定义路由权限”的方式实现管控：前端代码中固定定义所有路由，并为需要权限管控的路由配置 <code>authority</code> 字段（指定可访问的角色码）；系统初始化时仅加载通用路由，用户登录后获取其角色信息，通过角色匹配筛选出可访问的路由，再通过 <code>router.addRoute</code> 动态添加到路由实例中，实现权限过滤。</p><h4 id="适用场景与优缺点-1" tabindex="-1"><a class="header-anchor" href="#适用场景与优缺点-1"><span>适用场景与优缺点</span></a></h4><ul><li><strong>适用场景</strong>：角色体系固定（如仅超级管理员、普通管理员、用户三类角色）、权限变更频率低的简单系统。</li><li><strong>优点</strong>：前后端耦合度低，前端独立管控权限，开发简单、调试便捷。</li><li><strong>缺点</strong>：权限变更需修改前端代码并重新部署，扩展性差；角色数量增多时，路由权限配置维护成本会显著上升。</li></ul><h4 id="启用步骤与核心配置-1" tabindex="-1"><a class="header-anchor" href="#启用步骤与核心配置-1"><span>启用步骤与核心配置</span></a></h4><h5 id="_1-修改环境变量-1" tabindex="-1"><a class="header-anchor" href="#_1-修改环境变量-1"><span>1. 修改环境变量：</span></a></h5><p>编辑 <code>.env</code> 配置文件，将 <code>VITE_ROUTER_ACCESS_MODE</code> 的值设置为 <code>frontend</code>，启用前端控制模式：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"># 路由的访问模式：frontend（前端控制），backend（后端控制）</span>
<span class="line"><span class="token constant">VITE_ROUTER_ACCESS_MODE</span><span class="token operator">=</span>frontend</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_2-配置路由权限标识" tabindex="-1"><a class="header-anchor" href="#_2-配置路由权限标识"><span>2. 配置路由权限标识：</span></a></h5><p>在前端预定义的路由数组中，为需要权限管控的路由添加 <code>meta.authority</code> 字段，值为后端约定的角色码数组（如<code>[&#39;super&#39;]</code> 表示仅超级管理员可访问）：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// 示例：系统管理模块路由配置（src/router/routes/system.ts）</span></span>
<span class="line"><span class="token keyword">const</span> system<span class="token operator">:</span> RouteRecordRaw<span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span></span>
<span class="line">  <span class="token punctuation">{</span></span>
<span class="line">    path<span class="token operator">:</span> <span class="token string">&#39;/system&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    name<span class="token operator">:</span> <span class="token string">&#39;System&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    component<span class="token operator">:</span> Layout<span class="token punctuation">,</span> <span class="token comment">// 布局组件</span></span>
<span class="line">    meta<span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">      title<span class="token operator">:</span> <span class="token string">&#39;系统管理&#39;</span><span class="token punctuation">,</span> <span class="token comment">// 菜单名称</span></span>
<span class="line">      authority<span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&#39;super&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;admin&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token comment">// 可访问角色：超级管理员、普通管理员</span></span>
<span class="line">      icon<span class="token operator">:</span> <span class="token string">&#39;icon-settings&#39;</span><span class="token punctuation">,</span> <span class="token comment">// 菜单图标</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    children<span class="token operator">:</span> <span class="token punctuation">[</span></span>
<span class="line">      <span class="token punctuation">{</span></span>
<span class="line">        path<span class="token operator">:</span> <span class="token string">&#39;user&#39;</span><span class="token punctuation">,</span></span>
<span class="line">        name<span class="token operator">:</span> <span class="token string">&#39;SystemUser&#39;</span><span class="token punctuation">,</span></span>
<span class="line">        meta<span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">          title<span class="token operator">:</span> <span class="token string">&#39;用户管理&#39;</span><span class="token punctuation">,</span></span>
<span class="line">          authority<span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&#39;super&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token comment">// 仅超级管理员可访问</span></span>
<span class="line">        <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>权限规则说明</strong>：未配置 <code>authority</code> 字段：所有用户可见（如首页、帮助中心）。</p><h5 id="_3-authority-为空数组" tabindex="-1"><a class="header-anchor" href="#_3-authority-为空数组"><span>3. authority 为空数组（[]）：</span></a></h5><p>所有用户不可见（如内部测试页面）。</p><h5 id="_4-authority-为角色码数组" tabindex="-1"><a class="header-anchor" href="#_4-authority-为角色码数组"><span>4. authority 为角色码数组：</span></a></h5><p>仅数组内角色的用户可见。</p><h5 id="_5-用户角色数据适配" tabindex="-1"><a class="header-anchor" href="#_5-用户角色数据适配"><span>5. 用户角色数据适配：</span></a></h5><p>前端权限筛选依赖用户角色信息，需确保后端返回的用户数据中包含 roles 字段（角色码列表数组），并在前端存储：</p><ol><li>Protobuf 定义（后端返回用户数据结构）</li></ol><div class="language-protobuf line-numbers-mode" data-highlighter="prismjs" data-ext="protobuf"><pre><code><span class="line"><span class="token keyword">message</span> <span class="token class-name">User</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">repeated</span> <span class="token builtin">string</span> roles <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span> <span class="token comment">// 角色码列表，如 [&quot;super&quot;, &quot;admin&quot;]</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>前端存储角色信息（src/store/auth.ts）</li></ol><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// 设置登录用户信息，确保 userInfo.roles 为角色码数组</span></span>
<span class="line">authStore<span class="token punctuation">.</span><span class="token function">setUserInfo</span><span class="token punctuation">(</span>userInfo<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">// 后续路由筛选会自动读取 userStore.userRoles 进行匹配</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="特殊场景-菜单可见但禁止访问" tabindex="-1"><a class="header-anchor" href="#特殊场景-菜单可见但禁止访问"><span>特殊场景：菜单可见但禁止访问</span></a></h4><p>部分业务场景下需实现“菜单可见但点击后跳转403无权限页面”（如引导普通用户申请权限），可通过配置 <code>meta.menuVisibleWithForbidden: true</code> 实现：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token keyword">const</span> system<span class="token operator">:</span> RouteRecordRaw<span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span></span>
<span class="line">  <span class="token punctuation">{</span></span>
<span class="line">    path<span class="token operator">:</span> <span class="token string">&#39;/report&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    name<span class="token operator">:</span> <span class="token string">&#39;Report&#39;</span><span class="token punctuation">,</span></span>
<span class="line">    meta<span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">      title<span class="token operator">:</span> <span class="token string">&#39;财务报表&#39;</span><span class="token punctuation">,</span></span>
<span class="line">      authority<span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&#39;super&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token comment">// 仅超级管理员可访问</span></span>
<span class="line">      menuVisibleWithForbidden<span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span> <span class="token comment">// 未授权用户可见菜单，点击跳转403</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="二、按钮级权限-管控操作执行权限" tabindex="-1"><a class="header-anchor" href="#二、按钮级权限-管控操作执行权限"><span>二、按钮级权限：管控操作执行权限</span></a></h2><p>按钮级权限是更细粒度的功能权限管控，用于控制用户能否执行特定操作（如“新增用户”“删除订单”“导出报表”）。GoWind Admin 支持通过「权限码（Permission Code）」和「角色码（Role Code）」两种维度实现按钮级权限控制，适配不同的权限管控粒度需求。</p><p>核心依赖 <code>@vben/access</code> 权限组件库，提供「组件方式」「API方式」「指令方式」三种使用形态，开发者可根据组件复用性、代码简洁性需求灵活选择。</p><h3 id="_2-1-权限码控制-推荐-最小粒度权限管控" tabindex="-1"><a class="header-anchor" href="#_2-1-权限码控制-推荐-最小粒度权限管控"><span>2.1 权限码控制（推荐：最小粒度权限管控）</span></a></h3><p>权限码是系统中最小粒度的权限标识，用于唯一标记单个操作权限（如 <code>user:add</code> 表示新增用户、<code>order:delete</code> 表示删除订单）。权限码由后端接口返回，前端通过判断当前用户是否拥有目标权限码，控制按钮的显示/隐藏。</p><h4 id="核心流程" tabindex="-1"><a class="header-anchor" href="#核心流程"><span>核心流程</span></a></h4><ol><li>用户登录后，前端调用<code>defRouterService.ListPermissionCode({})</code> 接口拉取当前用户的权限码列表。</li><li>前端将权限码列表存储到<code>accessStore</code> 中，供全局权限判断使用。</li><li>通过 <code>@vben/access</code> 提供的能力，基于权限码判断按钮是否显示。</li></ol><h4 id="核心代码-权限码获取与存储" tabindex="-1"><a class="header-anchor" href="#核心代码-权限码获取与存储"><span>核心代码（权限码获取与存储）</span></a></h4><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// src/store/auth.ts</span></span>
<span class="line"><span class="token comment">/**</span>
<span class="line"> * 登录后初始化用户信息与权限码</span>
<span class="line"> */</span></span>
<span class="line"><span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">initAuthData</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token comment">// 并行拉取用户信息和权限码</span></span>
<span class="line">  <span class="token keyword">const</span> <span class="token punctuation">[</span>fetchUserInfoResult<span class="token punctuation">,</span> accessCodes<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token builtin">Promise</span><span class="token punctuation">.</span><span class="token function">all</span><span class="token punctuation">(</span><span class="token punctuation">[</span></span>
<span class="line">    <span class="token function">fetchUserInfo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token comment">// 拉取用户基础信息</span></span>
<span class="line">    <span class="token function">fetchAccessCodes</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token comment">// 拉取权限码列表</span></span>
<span class="line">  <span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">  <span class="token keyword">const</span> userInfo <span class="token operator">=</span> fetchUserInfoResult<span class="token punctuation">;</span></span>
<span class="line">  <span class="token comment">// 存储用户信息到状态管理</span></span>
<span class="line">  userStore<span class="token punctuation">.</span><span class="token function">setUserInfo</span><span class="token punctuation">(</span>userInfo<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token comment">// 存储权限码到状态管理（accessCodes.codes 为权限码数组，如 [&quot;user:add&quot;, &quot;order:edit&quot;]）</span></span>
<span class="line">  accessStore<span class="token punctuation">.</span><span class="token function">setAccessCodes</span><span class="token punctuation">(</span>accessCodes<span class="token punctuation">.</span>codes<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">/**</span>
<span class="line"> * 拉取用户基础信息</span>
<span class="line"> */</span></span>
<span class="line"><span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">fetchUserInfo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">return</span> <span class="token punctuation">(</span><span class="token keyword">await</span> defAuthnService<span class="token punctuation">.</span><span class="token function">GetMe</span><span class="token punctuation">(</span><span class="token punctuation">{</span> id<span class="token operator">:</span> <span class="token number">0</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token keyword">as</span> UserInfo<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">/**</span>
<span class="line"> * 拉取用户权限码列表</span>
<span class="line"> */</span></span>
<span class="line"><span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">fetchAccessCodes</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">return</span> <span class="token keyword">await</span> defRouterService<span class="token punctuation">.</span><span class="token function">ListPermissionCode</span><span class="token punctuation">(</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="三种使用方式" tabindex="-1"><a class="header-anchor" href="#三种使用方式"><span>三种使用方式</span></a></h4><h4 id="方式1-组件方式-推荐-适合单个-少量按钮" tabindex="-1"><a class="header-anchor" href="#方式1-组件方式-推荐-适合单个-少量按钮"><span>方式1：组件方式（推荐，适合单个/少量按钮）</span></a></h4><p>使用 <code>AccessControl</code> 组件包裹按钮，通过 <code>codes</code> 属性指定所需权限码，<code>type=&quot;code&quot;</code> 表示基于权限码判断：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// src/views/system/user/index.vue</span></span>
<span class="line"><span class="token operator">&lt;</span>script lang<span class="token operator">=</span><span class="token string">&quot;ts&quot;</span> setup<span class="token operator">&gt;</span></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> AccessControl <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vben/access&#39;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token operator">&lt;</span><span class="token operator">/</span>script<span class="token operator">&gt;</span></span>
<span class="line"></span>
<span class="line"><span class="token operator">&lt;</span>template<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span><span class="token operator">!</span><span class="token operator">--</span> 需要指明 type<span class="token operator">=</span><span class="token string">&quot;code&quot;</span> <span class="token operator">--</span><span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>AccessControl <span class="token operator">:</span>codes<span class="token operator">=</span><span class="token string">&quot;[&#39;product:add&#39;]&quot;</span> type<span class="token operator">=</span><span class="token string">&quot;code&quot;</span><span class="token operator">&gt;</span></span>
<span class="line">    <span class="token operator">&lt;</span>Button<span class="token operator">&gt;</span> 添加商品 <span class="token punctuation">[</span><span class="token string">&quot;product:add&quot;</span><span class="token punctuation">]</span> <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span><span class="token operator">/</span>AccessControl<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>AccessControl <span class="token operator">:</span>codes<span class="token operator">=</span><span class="token string">&quot;[&#39;product:edit&#39;]&quot;</span> type<span class="token operator">=</span><span class="token string">&quot;code&quot;</span><span class="token operator">&gt;</span></span>
<span class="line">    <span class="token operator">&lt;</span>Button<span class="token operator">&gt;</span> 编辑商品 <span class="token punctuation">[</span><span class="token string">&quot;product:edit&quot;</span><span class="token punctuation">]</span> <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span><span class="token operator">/</span>AccessControl<span class="token operator">&gt;</span></span>
<span class="line"><span class="token operator">&lt;</span><span class="token operator">/</span>template<span class="token operator">&gt;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="方式2-api方式-适合复杂逻辑判断场景" tabindex="-1"><a class="header-anchor" href="#方式2-api方式-适合复杂逻辑判断场景"><span>方式2：API方式（适合复杂逻辑判断场景）</span></a></h4><p>通过 <code>useAccess</code>钩子获取 <code>hasAccessByCodes</code> 方法，在模板中通过<code>v-if</code> 控制按钮显示，支持结合其他业务逻辑判断：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// src/views/system/user/index.vue</span></span>
<span class="line"><span class="token operator">&lt;</span>script lang<span class="token operator">=</span><span class="token string">&quot;ts&quot;</span> setup<span class="token operator">&gt;</span></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> useAccess <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vben/access&#39;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">const</span> <span class="token punctuation">{</span> hasAccessByCodes <span class="token punctuation">}</span> <span class="token operator">=</span> <span class="token function">useAccess</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token operator">&lt;</span><span class="token operator">/</span>script<span class="token operator">&gt;</span></span>
<span class="line"></span>
<span class="line"><span class="token operator">&lt;</span>template<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>Button v<span class="token operator">-</span><span class="token keyword">if</span><span class="token operator">=</span><span class="token string">&quot;hasAccessByCodes([&#39;product:add&#39;])&quot;</span><span class="token operator">&gt;</span></span>
<span class="line">    添加商品 <span class="token punctuation">[</span><span class="token string">&quot;product:add&quot;</span><span class="token punctuation">]</span></span>
<span class="line">  <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>Button v<span class="token operator">-</span><span class="token keyword">if</span><span class="token operator">=</span><span class="token string">&quot;hasAccessByCodes([&#39;product:edit&#39;])&quot;</span><span class="token operator">&gt;</span></span>
<span class="line">    编辑商品 <span class="token punctuation">[</span><span class="token string">&quot;product:edit&quot;</span><span class="token punctuation">]</span></span>
<span class="line">  <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line"><span class="token operator">&lt;</span><span class="token operator">/</span>template<span class="token operator">&gt;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="方式3-指令方式-适合批量按钮权限控制-简洁高效" tabindex="-1"><a class="header-anchor" href="#方式3-指令方式-适合批量按钮权限控制-简洁高效"><span>方式3：指令方式（适合批量按钮权限控制，简洁高效）</span></a></h4><p>使用<code>v-access:code</code> 指令直接绑定权限码，支持单个权限码（字符串）或多个权限码（数组）：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// src/views/system/user/index.vue</span></span>
<span class="line"><span class="token operator">&lt;</span>template<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>Button <span class="token keyword">class</span><span class="token operator">=</span><span class="token string">&quot;mr-4&quot;</span> v<span class="token operator">-</span>access<span class="token operator">:</span>code<span class="token operator">=</span><span class="token string">&quot;&#39;product:add&#39;&quot;</span><span class="token operator">&gt;</span></span>
<span class="line">    添加商品 <span class="token punctuation">[</span><span class="token string">&quot;product:add&quot;</span><span class="token punctuation">]</span></span>
<span class="line">  <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>Button <span class="token keyword">class</span><span class="token operator">=</span><span class="token string">&quot;mr-4&quot;</span> v<span class="token operator">-</span>access<span class="token operator">:</span>code<span class="token operator">=</span><span class="token string">&quot;[&#39;product:edit&#39;]&quot;</span><span class="token operator">&gt;</span></span>
<span class="line">    编辑商品 <span class="token punctuation">[</span><span class="token string">&quot;product:edit&quot;</span><span class="token punctuation">]</span></span>
<span class="line">  <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line"><span class="token operator">&lt;</span><span class="token operator">/</span>template<span class="token operator">&gt;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-2-角色码控制-适配粗粒度操作管控" tabindex="-1"><a class="header-anchor" href="#_2-2-角色码控制-适配粗粒度操作管控"><span>2.2 角色码控制（适配粗粒度操作管控）</span></a></h3><p>角色码控制基于用户所属角色实现按钮权限管控，适用于对操作权限要求不精细的场景（如“所有管理员均可查看操作日志”）。核心依赖 <code>useUserStore</code> 中存储的<code>userRoles</code> 角色码列表，通过判断用户角色是否在目标角色范围内，控制按钮显示。</p><h4 id="核心逻辑-角色码获取与判断" tabindex="-1"><a class="header-anchor" href="#核心逻辑-角色码获取与判断"><span>核心逻辑（角色码获取与判断）</span></a></h4><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// src/store/user.ts</span></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> useUserStore <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vben/stores&#39;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">/**</span>
<span class="line"> * 角色权限判断：判断用户是否拥有目标角色中的任一角色</span>
<span class="line"> * @param roles 目标角色码列表</span>
<span class="line"> */</span></span>
<span class="line"><span class="token keyword">function</span> <span class="token function">hasAccessByRoles</span><span class="token punctuation">(</span>roles<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">const</span> userStore <span class="token operator">=</span> <span class="token function">useUserStore</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token keyword">const</span> userRoleSet <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Set</span><span class="token punctuation">(</span>userStore<span class="token punctuation">.</span>userRoles<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 用户当前角色集合</span></span>
<span class="line">  <span class="token comment">// 计算目标角色与用户角色的交集，有交集则拥有权限</span></span>
<span class="line">  <span class="token keyword">const</span> intersection <span class="token operator">=</span> roles<span class="token punctuation">.</span><span class="token function">filter</span><span class="token punctuation">(</span>item <span class="token operator">=&gt;</span> userRoleSet<span class="token punctuation">.</span><span class="token function">has</span><span class="token punctuation">(</span>item<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token keyword">return</span> intersection<span class="token punctuation">.</span>length <span class="token operator">&gt;</span> <span class="token number">0</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 角色码来源：用户登录时从后端拉取并存储</span></span>
<span class="line"><span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">fetchUserInfo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">const</span> userInfo <span class="token operator">=</span> <span class="token keyword">await</span> defAuthnService<span class="token punctuation">.</span><span class="token function">GetMe</span><span class="token punctuation">(</span><span class="token punctuation">{</span> id<span class="token operator">:</span> <span class="token number">0</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token comment">// 存储角色信息到状态管理</span></span>
<span class="line">  <span class="token keyword">const</span> roles <span class="token operator">=</span> userInfo<span class="token operator">?.</span>roles <span class="token operator">??</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">  userStore<span class="token punctuation">.</span><span class="token function">setUserRoles</span><span class="token punctuation">(</span>roles<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token keyword">return</span> userInfo<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="三种使用方式-1" tabindex="-1"><a class="header-anchor" href="#三种使用方式-1"><span>三种使用方式</span></a></h4><h5 id="方式1-组件方式" tabindex="-1"><a class="header-anchor" href="#方式1-组件方式"><span>方式1：组件方式</span></a></h5><p>使用 <code>AccessControl</code> 组件，通过 <code>type=&quot;role&quot;</code> 指定基于角色码判断：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// src/views/system/log/index.vue</span></span>
<span class="line"><span class="token operator">&lt;</span>script lang<span class="token operator">=</span><span class="token string">&quot;ts&quot;</span> setup<span class="token operator">&gt;</span></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> AccessControl <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vben/access&#39;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token operator">&lt;</span><span class="token operator">/</span>script<span class="token operator">&gt;</span></span>
<span class="line"></span>
<span class="line"><span class="token operator">&lt;</span>template<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>AccessControl <span class="token operator">:</span>codes<span class="token operator">=</span><span class="token string">&quot;[&#39;super&#39;]&quot;</span> type<span class="token operator">=</span><span class="token string">&quot;role&quot;</span><span class="token operator">&gt;</span></span>
<span class="line">    <span class="token operator">&lt;</span>Button<span class="token operator">&gt;</span> Super 角色可见 <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span><span class="token operator">/</span>AccessControl<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>AccessControl <span class="token operator">:</span>codes<span class="token operator">=</span><span class="token string">&quot;[&#39;admin&#39;]&quot;</span> type<span class="token operator">=</span><span class="token string">&quot;role&quot;</span><span class="token operator">&gt;</span></span>
<span class="line">    <span class="token operator">&lt;</span>Button<span class="token operator">&gt;</span> Admin 角色可见 <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span><span class="token operator">/</span>AccessControl<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>AccessControl <span class="token operator">:</span>codes<span class="token operator">=</span><span class="token string">&quot;[&#39;user&#39;]&quot;</span> type<span class="token operator">=</span><span class="token string">&quot;role&quot;</span><span class="token operator">&gt;</span></span>
<span class="line">    <span class="token operator">&lt;</span>Button<span class="token operator">&gt;</span> User 角色可见 <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span><span class="token operator">/</span>AccessControl<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>AccessControl <span class="token operator">:</span>codes<span class="token operator">=</span><span class="token string">&quot;[&#39;super&#39;, &#39;admin&#39;]&quot;</span> type<span class="token operator">=</span><span class="token string">&quot;role&quot;</span><span class="token operator">&gt;</span></span>
<span class="line">    <span class="token operator">&lt;</span>Button<span class="token operator">&gt;</span> Super <span class="token operator">&amp;</span> Admin 角色可见 <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span><span class="token operator">/</span>AccessControl<span class="token operator">&gt;</span></span>
<span class="line"><span class="token operator">&lt;</span><span class="token operator">/</span>template<span class="token operator">&gt;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="方式2-api方式" tabindex="-1"><a class="header-anchor" href="#方式2-api方式"><span>方式2：API方式</span></a></h5><p>通过 <code>useAccess</code> 钩子获取 <code>hasAccessByRoles</code> 方法，结合 <code>v-if</code> 控制显示：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// src/views/system/log/index.vue</span></span>
<span class="line"><span class="token operator">&lt;</span>script lang<span class="token operator">=</span><span class="token string">&quot;ts&quot;</span> setup<span class="token operator">&gt;</span></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> useAccess <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vben/access&#39;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">const</span> <span class="token punctuation">{</span> hasAccessByRoles <span class="token punctuation">}</span> <span class="token operator">=</span> <span class="token function">useAccess</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token operator">&lt;</span><span class="token operator">/</span>script<span class="token operator">&gt;</span></span>
<span class="line"></span>
<span class="line"><span class="token operator">&lt;</span>template<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>Button v<span class="token operator">-</span><span class="token keyword">if</span><span class="token operator">=</span><span class="token string">&quot;hasAccessByRoles([&#39;super&#39;])&quot;</span><span class="token operator">&gt;</span> Super 账号可见 <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>Button v<span class="token operator">-</span><span class="token keyword">if</span><span class="token operator">=</span><span class="token string">&quot;hasAccessByRoles([&#39;admin&#39;])&quot;</span><span class="token operator">&gt;</span> Admin 账号可见 <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>Button v<span class="token operator">-</span><span class="token keyword">if</span><span class="token operator">=</span><span class="token string">&quot;hasAccessByRoles([&#39;user&#39;])&quot;</span><span class="token operator">&gt;</span> User 账号可见 <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>Button v<span class="token operator">-</span><span class="token keyword">if</span><span class="token operator">=</span><span class="token string">&quot;hasAccessByRoles([&#39;super&#39;, &#39;admin&#39;])&quot;</span><span class="token operator">&gt;</span></span>
<span class="line">    Super <span class="token operator">&amp;</span> Admin 账号可见</span>
<span class="line">  <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line"><span class="token operator">&lt;</span><span class="token operator">/</span>template<span class="token operator">&gt;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="方式3-指令方式" tabindex="-1"><a class="header-anchor" href="#方式3-指令方式"><span>方式3：指令方式</span></a></h5><p>使用 <code>v-access:role</code> 指令直接绑定角色码，支持单个或多个角色：</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// src/views/system/log/index.vue</span></span>
<span class="line"><span class="token operator">&lt;</span>template<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>Button <span class="token keyword">class</span><span class="token operator">=</span><span class="token string">&quot;mr-4&quot;</span> v<span class="token operator">-</span>access<span class="token operator">:</span>role<span class="token operator">=</span><span class="token string">&quot;&#39;super&#39;&quot;</span><span class="token operator">&gt;</span> Super 角色可见 <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>Button <span class="token keyword">class</span><span class="token operator">=</span><span class="token string">&quot;mr-4&quot;</span> v<span class="token operator">-</span>access<span class="token operator">:</span>role<span class="token operator">=</span><span class="token string">&quot;[&#39;super&#39;]&quot;</span><span class="token operator">&gt;</span> Super 角色可见 <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>Button <span class="token keyword">class</span><span class="token operator">=</span><span class="token string">&quot;mr-4&quot;</span> v<span class="token operator">-</span>access<span class="token operator">:</span>role<span class="token operator">=</span><span class="token string">&quot;[&#39;admin&#39;]&quot;</span><span class="token operator">&gt;</span> Admin 角色可见 <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>Button <span class="token keyword">class</span><span class="token operator">=</span><span class="token string">&quot;mr-4&quot;</span> v<span class="token operator">-</span>access<span class="token operator">:</span>role<span class="token operator">=</span><span class="token string">&quot;[&#39;user&#39;]&quot;</span><span class="token operator">&gt;</span> User 角色可见 <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line">  <span class="token operator">&lt;</span>Button <span class="token keyword">class</span><span class="token operator">=</span><span class="token string">&quot;mr-4&quot;</span> v<span class="token operator">-</span>access<span class="token operator">:</span>role<span class="token operator">=</span><span class="token string">&quot;[&#39;super&#39;, &#39;admin&#39;]&quot;</span><span class="token operator">&gt;</span></span>
<span class="line">    Super <span class="token operator">&amp;</span> Admin 角色可见</span>
<span class="line">  <span class="token operator">&lt;</span><span class="token operator">/</span>Button<span class="token operator">&gt;</span></span>
<span class="line"><span class="token operator">&lt;</span><span class="token operator">/</span>template<span class="token operator">&gt;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="三、权限控制最佳实践" tabindex="-1"><a class="header-anchor" href="#三、权限控制最佳实践"><span>三、权限控制最佳实践</span></a></h2><h3 id="_3-1-控制方式选择建议" tabindex="-1"><a class="header-anchor" href="#_3-1-控制方式选择建议"><span>3.1 控制方式选择建议</span></a></h3><table><thead><tr><th>管控场景</th><th>推荐控制方式</th><th>理由</th></tr></thead><tbody><tr><td>复杂多租户、动态角色权限</td><td>页面级：后端控制；按钮级：权限码控制</td><td>后端统一管控权限配置，适配频繁变更，减少前后端协同成本</td></tr><tr><td>简单固定角色（3类以内）、权限变更少</td><td>页面级：前端控制；按钮级：角色码控制</td><td>前端独立开发调试，降低初期开发成本，适配简单场景</td></tr><tr><td>核心操作（如删除、导出）</td><td>权限码控制 + 后端接口二次校验</td><td>前端控制仅隐藏按钮，后端接口校验防止恶意请求，双重保障安全</td></tr></tbody></table><h3 id="_3-2-核心注意事项" tabindex="-1"><a class="header-anchor" href="#_3-2-核心注意事项"><span>3.2 核心注意事项</span></a></h3><ul><li><strong>前端权限仅为“显示控制”，不可替代后端校验</strong>：前端可通过隐藏菜单/按钮阻止普通用户操作，但恶意用户可能通过伪造请求绕过前端控制。因此，所有权限相关的接口必须在后端进行二次校验（如验证用户是否拥有操作权限码），确保数据安全。</li><li><strong>权限数据缓存与刷新</strong>：用户角色/权限变更后，需及时刷新前端权限状态（如重新拉取权限码、重新生成路由），避免权限变更不生效。</li><li><strong>异常降级处理</strong>：后端路由/权限码接口请求失败时，需添加降级逻辑（如跳转403页、提示“权限加载失败，请重试”），提升用户体验。</li></ul><h2 id="四、项目源码与参考资料" tabindex="-1"><a class="header-anchor" href="#四、项目源码与参考资料"><span>四、项目源码与参考资料</span></a></h2><h3 id="_4-1-项目源码" tabindex="-1"><a class="header-anchor" href="#_4-1-项目源码"><span>4.1 项目源码</span></a></h3><ul><li>Gitee（国内访问速度快）：<a href="https://gitee.com/tx7do/go-wind-admin" target="_blank" rel="noopener noreferrer">https://gitee.com/tx7do/go-wind-admin</a></li><li>GitHub：<a href="https://github.com/tx7do/go-wind-admin" target="_blank" rel="noopener noreferrer">https://github.com/tx7do/go-wind-admin</a></li></ul><h3 id="_4-2-参考资料" tabindex="-1"><a class="header-anchor" href="#_4-2-参考资料"><span>4.2 参考资料</span></a></h3><ul><li>Vben Admin 权限系统官方文档：<a href="https://doc.vben.pro/guide/in-depth/access.html" target="_blank" rel="noopener noreferrer">https://doc.vben.pro/guide/in-depth/access.html</a></li><li>GoWind Admin 后端权限接口文档：<a href="http://localhost:7788/docs/openapi.yaml" target="_blank" rel="noopener noreferrer">http://localhost:7788/docs/openapi.yaml</a>（本地部署后访问）</li></ul>`,88)])])}const i=n(t,[["render",o]]),r=JSON.parse('{"path":"/posts/go_wind_admin_frontend_access_control.html","title":"GoWind Admin｜风行 — 开箱即用的企业级全栈中后台框架：前端权限控制","lang":"zh-CN","frontmatter":{"date":"2020-01-01T00:00:00.000Z","category":["GoWind风行"],"tag":["Golang","Go-Kratos","GoWind"],"sticky":10},"headers":[{"level":2,"title":"一、页面级权限：管控页面访问边界","slug":"一、页面级权限-管控页面访问边界","link":"#一、页面级权限-管控页面访问边界","children":[{"level":3,"title":"1.1 后端控制模式（推荐复杂权限场景）","slug":"_1-1-后端控制模式-推荐复杂权限场景","link":"#_1-1-后端控制模式-推荐复杂权限场景","children":[]},{"level":3,"title":"1.2 前端控制模式（适配简单固定角色场景）","slug":"_1-2-前端控制模式-适配简单固定角色场景","link":"#_1-2-前端控制模式-适配简单固定角色场景","children":[]}]},{"level":2,"title":"二、按钮级权限：管控操作执行权限","slug":"二、按钮级权限-管控操作执行权限","link":"#二、按钮级权限-管控操作执行权限","children":[{"level":3,"title":"2.1 权限码控制（推荐：最小粒度权限管控）","slug":"_2-1-权限码控制-推荐-最小粒度权限管控","link":"#_2-1-权限码控制-推荐-最小粒度权限管控","children":[]},{"level":3,"title":"2.2 角色码控制（适配粗粒度操作管控）","slug":"_2-2-角色码控制-适配粗粒度操作管控","link":"#_2-2-角色码控制-适配粗粒度操作管控","children":[]}]},{"level":2,"title":"三、权限控制最佳实践","slug":"三、权限控制最佳实践","link":"#三、权限控制最佳实践","children":[{"level":3,"title":"3.1 控制方式选择建议","slug":"_3-1-控制方式选择建议","link":"#_3-1-控制方式选择建议","children":[]},{"level":3,"title":"3.2 核心注意事项","slug":"_3-2-核心注意事项","link":"#_3-2-核心注意事项","children":[]}]},{"level":2,"title":"四、项目源码与参考资料","slug":"四、项目源码与参考资料","link":"#四、项目源码与参考资料","children":[{"level":3,"title":"4.1 项目源码","slug":"_4-1-项目源码","link":"#_4-1-项目源码","children":[]},{"level":3,"title":"4.2 参考资料","slug":"_4-2-参考资料","link":"#_4-2-参考资料","children":[]}]}],"git":{"updatedTime":1774788457000,"contributors":[{"name":"Bobo","username":"Bobo","email":"yanglinbo@gmail.com","commits":11,"url":"https://github.com/Bobo"}],"changelog":[{"hash":"a3e88b19cfead00baa606aa5110b2802dac32768","time":1774788457000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: REBUILD."},{"hash":"9ee9593d10296afa6d6a136d0fec19daa5fa3aad","time":1769485475000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: add posts."},{"hash":"010e3215f55190804ae072b007c76eaf933f80c7","time":1765524468000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: edit posts"},{"hash":"ae111c1195e0474d663bce54e67cfce0cfdaa8fe","time":1765461806000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: edit posts."},{"hash":"b7d9dbdec999dd456aea8ff6ac6fed7e0ba6f829","time":1749356906000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: edit post."},{"hash":"0c363196f58757303a830b0fa3826532562d7343","time":1749355446000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: edit post."},{"hash":"7e42dbb4e66dfb7c36bda080e85d48a6e07cf659","time":1744077635000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: edit posts."},{"hash":"241cd3394ef422ea119def33c84077bbffa5ab62","time":1744077027000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: edit posts."},{"hash":"cc6ca38aa76db4e48da3bacd90f7f19d8b859588","time":1740666012000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: edit posts."},{"hash":"c83b3a8bd74fcb66913ce89910ad450947ad9849","time":1739669306000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: add posts."},{"hash":"1c6d541f0c3fb794164eb41ba05be309112ee4af","time":1739114363000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: add post."}]},"filePathRelative":"posts/go_wind_admin_frontend_access_control.md","excerpt":"\\n<p>在企业级中后台系统中，前端权限控制是保障数据安全、规范用户操作边界的核心能力。风行·GoWind Admin 前端权限控制核心聚焦于<strong>功能权限管控</strong>，根据控制粒度的不同，分为「页面级权限」和「按钮级权限」两大模块，覆盖从“页面访问”到“操作执行”的全链路权限管控需求。本文将详细拆解两种权限的实现原理、启用方式、核心代码及最佳实践，助力开发者快速落地权限管控方案。</p>\\n<h2>一、页面级权限：管控页面访问边界</h2>\\n<p>页面级权限的核心目标是控制用户能否访问特定页面，主要通过「菜单隐藏」和「路由拦截」两种手段实现——未授权用户既无法在侧边栏看到目标菜单，也无法通过直接输入URL跳过菜单访问页面，进而实现对用户访问“财务报表”“人事管理”等核心页面的精准管控。</p>"}');export{i as comp,r as data};
